  1→//! Docker and Podman sandbox backends.
  2→
  3→use {
  4→    async_trait::async_trait,
  5→    tracing::{debug, info, warn},
  6→};
  7→
  8→use {
  9→    super::{
 10→        containers::{
 11→            rebuildable_sandbox_image_tag, sandbox_image_dockerfile, sandbox_image_exists,
 12→            sandbox_image_tag,
 13→        },
 14→        host::provision_packages,
 15→        paths::{
 16→            ensure_sandbox_home_persistence_host_dir, host_visible_data_dir,
 17→            resolve_home_persistence_guest_path_on_host, resolve_workspace_guest_path_on_host,
 18→        },
 19→        types::{
 20→            BuildImageResult, DEFAULT_SANDBOX_IMAGE, NetworkPolicy, SANDBOX_HOME_DIR, Sandbox,
 21→            SandboxConfig, SandboxId, WorkspaceMount, canonical_sandbox_packages,
 22→            truncate_output_for_display,
 23→        },
 24→    },
 25→    crate::{
 26→        error::{Error, Result},
 27→        exec::{ExecOpts, ExecResult},
 28→        sandbox::file_system::{
 29→            SandboxListFilesResult, SandboxReadResult, native_host_list_files,
 30→            native_host_read_file, native_host_write_file, oci_container_list_files,
 31→            oci_container_read_file, oci_container_write_file, remap_host_list_result_to_guest,
 32→        },
 33→    },
 34→};
 35→
 36→/// Docker/Podman-based sandbox implementation.
 37→///
 38→/// The `cli` field selects the container CLI binary (`"docker"` or `"podman"`).
 39→/// Podman's CLI is a drop-in replacement for Docker, so both backends share
 40→/// this single implementation.
 41→pub struct DockerSandbox {
 42→    pub config: SandboxConfig,
 43→    cli: &'static str,
 44→    backend_label: &'static str,
 45→}
 46→
 47→impl DockerSandbox {
 48→    pub fn new(config: SandboxConfig) -> Self {
 49→        Self {
 50→            config,
 51→            cli: "docker",
 52→            backend_label: "docker",
 53→        }
 54→    }
 55→
 56→    pub fn podman(config: SandboxConfig) -> Self {
 57→        Self {
 58→            config,
 59→            cli: "podman",
 60→            backend_label: "podman",
 61→        }
 62→    }
 63→
 64→    fn image(&self) -> &str {
 65→        self.config
 66→            .image
 67→            .as_deref()
 68→            .unwrap_or(DEFAULT_SANDBOX_IMAGE)
 69→    }
 70→
 71→    fn container_prefix(&self) -> &str {
 72→        self.config
 73→            .container_prefix
 74→            .as_deref()
 75→            .unwrap_or("moltis-sandbox")
 76→    }
 77→
 78→    pub(crate) fn container_name(&self, id: &SandboxId) -> String {
 79→        format!("{}-{}", self.container_prefix(), id.key)
 80→    }
 81→
 82→    fn image_repo(&self) -> &str {
 83→        self.container_prefix()
 84→    }
 85→
 86→    fn mounted_host_path(&self, id: &SandboxId, guest_path: &str) -> Option<std::path::PathBuf> {
 87→        let guest_path = std::path::Path::new(guest_path);
 88→        resolve_workspace_guest_path_on_host(&self.config, Some(self.cli), guest_path).or_else(
 89→            || {
 90→                resolve_home_persistence_guest_path_on_host(
 91→                    &self.config,
 92→                    Some(self.cli),
 93→                    id,
 94→                    guest_path,
 95→                )
 96→            },
 97→        )
 98→    }
 99→
100→    pub(crate) fn resource_args(&self) -> Vec<String> {
101→        let mut args = Vec::new();
102→        let limits = &self.config.resource_limits;
103→        if let Some(ref mem) = limits.memory_limit {
104→            args.extend(["--memory".to_string(), mem.clone()]);
105→        }
106→        if let Some(cpu) = limits.cpu_quota {
107→            args.extend(["--cpus".to_string(), cpu.to_string()]);
108→        }
109→        if let Some(pids) = limits.pids_max {
110→            args.extend(["--pids-limit".to_string(), pids.to_string()]);
111→        }
112→        args
113→    }
114→
115→    pub(crate) fn network_run_args(&self) -> Vec<String> {
116→        match self.config.network {
117→            NetworkPolicy::Blocked => vec!["--network=none".to_string()],
118→            NetworkPolicy::Trusted => {
119→                // Ensure the container can reach the host proxy on all
120→                // platforms (Linux needs --add-host; macOS Docker Desktop
121→                // resolves host.docker.internal automatically).
122→                let gateway = self.resolve_host_gateway();
123→                vec![format!("--add-host=host.docker.internal:{gateway}")]
124→            },
125→            NetworkPolicy::Bypass => Vec::new(),
126→        }
127→    }
128→
129→    /// Resolve the IP that containers use to reach the host.
130→    ///
131→    /// Docker (and Podman >= 5.0) support the special `host-gateway` token in
132→    /// `--add-host`.  Older Podman versions reject it with:
133→    ///
134→    ///   Error: invalid IP address in add-host: "host-gateway"
135→    ///
136→    /// For those we resolve the address ourselves: rootless Podman (< 5.0) uses
137→    /// slirp4netns by default, which maps the host to `10.0.2.2`.  Rootful
138→    /// Podman uses a bridge whose gateway we can query via
139→    /// `podman network inspect`.
140→    pub(crate) fn resolve_host_gateway(&self) -> String {
141→        if self.cli != "podman" {
142→            return "host-gateway".to_string();
143→        }
144→
145→        if podman_supports_host_gateway() {
146→            return "host-gateway".to_string();
147→        }
148→
149→        // Podman < 5.0 — resolve the address manually.
150→        podman_resolve_host_ip().unwrap_or_else(|| {
151→            debug!(
152→                "could not resolve host gateway IP for podman; \
153→                 falling back to host-gateway (may fail)"
154→            );
155→            "host-gateway".to_string()
156→        })
157→    }
158→
159→    pub(crate) fn proxy_exec_env_args(&self) -> Vec<String> {
160→        if self.config.network != NetworkPolicy::Trusted {
161→            return Vec::new();
162→        }
163→        let proxy_url = format!(
164→            "http://host.docker.internal:{}",
165→            moltis_network_filter::DEFAULT_PROXY_PORT
166→        );
167→        let mut args = Vec::new();
168→        for key in ["HTTP_PROXY", "http_proxy", "HTTPS_PROXY", "https_proxy"] {
169→            args.extend(["-e".to_string(), format!("{key}={proxy_url}")]);
170→        }
171→        for key in ["NO_PROXY", "no_proxy"] {
172→            args.extend(["-e".to_string(), format!("{key}=localhost,127.0.0.1,::1")]);
173→        }
174→        args
175→    }
176→
177→    /// Security hardening flags for `docker run`.
178→    ///
179→    /// `is_prebuilt` controls whether `--read-only` is applied: prebuilt images
180→    /// already have packages baked in so the root FS can be read-only, while
181→    /// non-prebuilt images need a writable root for `apt-get` provisioning.
182→    pub(crate) fn hardening_args(is_prebuilt: bool, cli: &str) -> Vec<String> {
183→        let mut args = vec![
184→            // --- Capability / privilege ---
185→            "--cap-drop".to_string(),
186→            "ALL".to_string(),
187→            "--security-opt".to_string(),
188→            "no-new-privileges".to_string(),
189→            // --- Writable tmpfs mounts ---
190→            "--tmpfs".to_string(),
191→            "/tmp:rw,nosuid,size=256m".to_string(),
192→            "--tmpfs".to_string(),
193→            "/run:rw,nosuid,size=64m".to_string(),
194→            // --- Host metadata isolation ---
195→            // Give the container its own hostname so /proc/sys/kernel/hostname
196→            // and the `hostname` command do not reveal the host identity.
197→            "--hostname".to_string(),
198→            "sandbox".to_string(),
199→        ];
200→        // Mask /sys subtrees that expose host hardware identifiers
201→        // (serial numbers, BIOS/UEFI data, disk models, LUKS UUIDs).
202→        // Empty read-only tmpfs overlays hide the underlying sysfs entries.
203→        //
204→        // Podman is excluded: its OCI runtime performs "tmpcopyup" on sysfs
205→        // tmpfs mounts, copying directory contents into the tmpfs first.
206→        // With --cap-drop ALL some sysfs files are permission-denied even for
207→        // root, causing the mount (and container startup) to fail.  Podman
208→        // already masks /sys/firmware via its built-in OCI MaskedPaths.
209→        if cli != "podman" {
210→            args.extend([
211→                "--tmpfs".to_string(),
212→                "/sys/firmware:ro,nosuid".to_string(),
213→                "--tmpfs".to_string(),
214→                "/sys/class/dmi:ro,nosuid".to_string(),
215→                "--tmpfs".to_string(),
216→                "/sys/devices/virtual/dmi:ro,nosuid".to_string(),
217→                "--tmpfs".to_string(),
218→                "/sys/class/block:ro,nosuid".to_string(),
219→            ]);
220→        }
221→        if is_prebuilt {
222→            args.push("--read-only".to_string());
223→        }
224→        args
225→    }
226→
227→    pub(crate) fn workspace_args(&self) -> Vec<String> {
228→        let guest_workspace_dir = moltis_config::data_dir();
229→        let host_workspace_dir = host_visible_data_dir(&self.config, Some(self.cli));
230→        let guest_workspace_dir_str = guest_workspace_dir.display().to_string();
231→        let host_workspace_dir_str = host_workspace_dir.display().to_string();
232→        match self.config.workspace_mount {
233→            WorkspaceMount::Ro => vec![
234→                "-v".to_string(),
235→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:ro"),
236→            ],
237→            WorkspaceMount::Rw => vec![
238→                "-v".to_string(),
239→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:rw"),
240→            ],
241→            WorkspaceMount::None => Vec::new(),
242→        }
243→    }
244→
245→    pub(crate) fn home_persistence_args(&self, id: &SandboxId) -> Result<Vec<String>> {
246→        let Some(host_dir) =
247→            ensure_sandbox_home_persistence_host_dir(&self.config, Some(self.cli), id)?
248→        else {
249→            return Ok(Vec::new());
250→        };
251→        let volume = format!("{}:{SANDBOX_HOME_DIR}:rw", host_dir.display());
252→        Ok(vec!["-v".to_string(), volume])
253→    }
254→
255→    async fn resolve_local_image(&self, requested_image: &str) -> Result<String> {
256→        if sandbox_image_exists(self.cli, requested_image).await {
257→            return Ok(requested_image.to_string());
258→        }
259→
260→        let base_image = self.image().to_string();
261→        let packages = self.config.packages.clone();
262→        let Some(rebuild_tag) = rebuildable_sandbox_image_tag(
263→            requested_image,
264→            self.image_repo(),
265→            &base_image,
266→            &packages,
267→        ) else {
268→            return Ok(requested_image.to_string());
269→        };
270→
271→        if requested_image == rebuild_tag {
272→            info!(
273→                image = requested_image,
274→                "sandbox image missing locally, rebuilding on demand"
275→            );
276→        } else {
277→            warn!(
278→                requested = requested_image,
279→                rebuilt = %rebuild_tag,
280→                "requested sandbox image missing locally, using deterministic tag from current config"
281→            );
282→        }
283→
284→        let Some(result) = self.build_image(&base_image, &packages).await? else {
285→            return Ok(requested_image.to_string());
286→        };
287→        Ok(result.tag)
288→    }
289→}
