291→#[async_trait]
292→impl Sandbox for DockerSandbox {
293→    fn backend_name(&self) -> &'static str {
294→        self.backend_label
295→    }
296→
297→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
298→        let name = self.container_name(id);
299→
300→        // Check if container already running.
301→        let check = tokio::process::Command::new(self.cli)
302→            .args(["inspect", "--format", "{{.State.Running}}", &name])
303→            .output()
304→            .await;
305→
306→        if let Ok(output) = check {
307→            let stdout = String::from_utf8_lossy(&output.stdout);
308→            if stdout.trim() == "true" {
309→                return Ok(());
310→            }
311→        }
312→
313→        // Resolve image first so we know whether it's prebuilt (affects hardening).
314→        let requested_image = image_override.unwrap_or_else(|| self.image());
315→        let image = self.resolve_local_image(requested_image).await?;
316→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
317→
318→        // Start a new container.
319→        let mut args = vec![
320→            "run".to_string(),
321→            "-d".to_string(),
322→            "--name".to_string(),
323→            name.clone(),
324→        ];
325→
326→        args.extend(self.network_run_args());
327→
328→        if let Some(ref tz) = self.config.timezone {
329→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
330→        }
331→
332→        args.extend(self.resource_args());
333→        args.extend(Self::hardening_args(is_prebuilt, self.cli));
334→        args.extend(self.workspace_args());
335→        args.extend(self.home_persistence_args(id)?);
336→
337→        args.push(image.clone());
338→        args.extend(["sleep".to_string(), "infinity".to_string()]);
339→
340→        let output = tokio::process::Command::new(self.cli)
341→            .args(&args)
342→            .output()
343→            .await?;
344→
345→        if !output.status.success() {
346→            let stderr = String::from_utf8_lossy(&output.stderr);
347→            return Err(Error::message(format!(
348→                "{} run failed: {}",
349→                self.cli,
350→                stderr.trim()
351→            )));
352→        }
353→
354→        // Skip provisioning if the image is a pre-built instance sandbox image
355→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
356→        if !is_prebuilt {
357→            provision_packages(self.cli, &name, &self.config.packages).await?;
358→        }
359→
360→        Ok(())
361→    }
362→
363→    async fn build_image(
364→        &self,
365→        base: &str,
366→        packages: &[String],
367→    ) -> Result<Option<BuildImageResult>> {
368→        if packages.is_empty() {
369→            return Ok(None);
370→        }
371→
372→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
373→
374→        // Check if image already exists.
375→        if sandbox_image_exists(self.cli, &tag).await {
376→            info!(
377→                tag,
378→                "pre-built sandbox image already exists, skipping build"
379→            );
380→            return Ok(Some(BuildImageResult { tag, built: false }));
381→        }
382→
383→        // Generate Dockerfile in a temp dir.
384→        let tmp_dir =
385→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
386→        std::fs::create_dir_all(&tmp_dir)?;
387→
388→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
389→        let dockerfile = sandbox_image_dockerfile(base, packages);
390→        let dockerfile_path = tmp_dir.join("Dockerfile");
391→        std::fs::write(&dockerfile_path, &dockerfile)?;
392→
393→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
394→
395→        let output = tokio::process::Command::new(self.cli)
396→            .args(["build", "-t", &tag, "-f"])
397→            .arg(&dockerfile_path)
398→            .arg(&tmp_dir)
399→            .stdout(std::process::Stdio::piped())
400→            .stderr(std::process::Stdio::piped())
401→            .output()
402→            .await;
403→
404→        // Clean up temp dir regardless of result.
405→        let _ = std::fs::remove_dir_all(&tmp_dir);
406→
407→        let output = output?;
408→        if !output.status.success() {
409→            let stderr = String::from_utf8_lossy(&output.stderr);
410→            return Err(Error::message(format!(
411→                "{} build failed for {tag}: {}",
412→                self.cli,
413→                stderr.trim()
414→            )));
415→        }
416→
417→        info!(tag, "pre-built sandbox image ready");
418→        Ok(Some(BuildImageResult { tag, built: true }))
419→    }
420→
421→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
422→        let name = self.container_name(id);
423→
424→        let mut args = vec!["exec".to_string()];
425→
426→        if let Some(ref dir) = opts.working_dir {
427→            args.extend(["-w".to_string(), dir.display().to_string()]);
428→        }
429→
430→        // Inject proxy env vars so traffic routes through the trusted-network
431→        // proxy running on the host.
432→        args.extend(self.proxy_exec_env_args());
433→
434→        for (k, v) in &opts.env {
435→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
436→        }
437→
438→        args.push(name);
439→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
440→
441→        let child = tokio::process::Command::new(self.cli)
442→            .args(&args)
443→            .stdout(std::process::Stdio::piped())
444→            .stderr(std::process::Stdio::piped())
445→            .stdin(std::process::Stdio::null())
446→            .spawn()?;
447→
448→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
449→
450→        match result {
451→            Ok(Ok(output)) => {
452→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
453→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
454→
455→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
456→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
457→
458→                Ok(ExecResult {
459→                    stdout,
460→                    stderr,
461→                    exit_code: output.status.code().unwrap_or(-1),
462→                })
463→            },
464→            Ok(Err(e)) => {
465→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
466→            },
467→            Err(_) => {
468→                return Err(Error::message(format!(
469→                    "{} exec timed out after {}s",
470→                    self.cli,
471→                    opts.timeout.as_secs()
472→                )));
473→            },
474→        }
475→    }
476→
477→    async fn read_file(
478→        &self,
479→        id: &SandboxId,
480→        file_path: &str,
481→        max_bytes: u64,
482→    ) -> Result<SandboxReadResult> {
483→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
484→            return native_host_read_file(
485→                host_path
486→                    .to_str()
487→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
488→                max_bytes,
489→            )
490→            .await;
491→        }
492→
493→        let container_name = self.container_name(id);
494→        oci_container_read_file(self.cli, &container_name, file_path, max_bytes).await
495→    }
496→
497→    async fn write_file(
498→        &self,
499→        id: &SandboxId,
500→        file_path: &str,
501→        content: &[u8],
502→    ) -> Result<Option<serde_json::Value>> {
503→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
504→            return native_host_write_file(
505→                host_path
506→                    .to_str()
507→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
508→                content,
509→            )
510→            .await;
511→        }
512→
513→        let container_name = self.container_name(id);
514→        oci_container_write_file(self.cli, &container_name, file_path, content).await
515→    }
516→
517→    async fn list_files(&self, id: &SandboxId, root: &str) -> Result<SandboxListFilesResult> {
518→        if let Some(host_path) = self.mounted_host_path(id, root) {
519→            let host_files = native_host_list_files(
520→                host_path
521→                    .to_str()
522→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
523→            )
524→            .await?;
525→            return remap_host_list_result_to_guest(root, &host_path, host_files);
526→        }
527→
528→        let container_name = self.container_name(id);
529→        oci_container_list_files(self.cli, &container_name, root).await
530→    }
531→
532→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
533→        let name = self.container_name(id);
534→        let _ = tokio::process::Command::new(self.cli)
535→            .args(["rm", "-f", &name])
536→            .output()
537→            .await;
538→        Ok(())
539→    }
540→}
