590→/// Return `true` when the installed Podman version supports `host-gateway`
591→/// in `--add-host` (added in Podman 5.0).
592→pub(crate) fn podman_supports_host_gateway() -> bool {
593→    let Ok(output) = std::process::Command::new("podman")
594→        .args(["version", "--format", "{{.Client.Version}}"])
595→        .output()
596→    else {
597→        return false;
598→    };
599→    let version_str = String::from_utf8_lossy(&output.stdout);
600→    let major: u32 = version_str
601→        .trim()
602→        .split('.')
603→        .next()
604→        .and_then(|s| s.parse().ok())
605→        .unwrap_or(0);
606→    major >= 5
607→}
608→
609→/// Resolve the host IP that a Podman container (< 5.0) can use to reach the
610→/// host.  Rootless Podman defaults to slirp4netns where the host is always
611→/// `10.0.2.2`.  Rootful Podman uses a bridge network whose gateway we query
612→/// with `podman network inspect`.
613→pub(crate) fn podman_resolve_host_ip() -> Option<String> {
614→    let rootless = std::process::Command::new("podman")
615→        .args(["info", "--format", "{{.Host.Security.Rootless}}"])
616→        .output()
617→        .ok()
618→        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
619→
620→    if rootless.as_deref() == Some("true") {
621→        // slirp4netns (default rootless network before Podman 5.0) maps the
622→        // host to 10.0.2.2.
623→        return Some("10.0.2.2".to_string());
624→    }
625→
626→    // Rootful — ask for the gateway of the default "podman" network.
627→    let output = std::process::Command::new("podman")
628→        .args([
629→            "network",
630→            "inspect",
631→            "podman",
632→            "--format",
633→            "{{(index .Subnets 0).Gateway}}",
634→        ])
635→        .output()
636→        .ok()?;
637→    let gateway = String::from_utf8_lossy(&output.stdout).trim().to_string();
638→    if gateway.is_empty() {
639→        None
640→    } else {
641→        Some(gateway)
642→    }
643→}
